class TrieNode:
    def __init__(self):
        self.children = {}
        self.is_end_of_word = False

class Trie:
    def __init__(self):
        self.root = TrieNode()

    def insert(self, word: str) -> None:
        node = self.root
        for char in word:
            if char not in node.children:
                node.children[char] = TrieNode()
            node = node.children[char]
        node.is_end_of_word = True

    def _find_prefix_node(self, prefix: str) -> TrieNode:
        node = self.root
        for char in prefix:
            if char not in node.children:
                return None
            node = node.children[char]
        return node

    def _collect_all_words_from_node(self, node: TrieNode, current_prefix: str, results: list) -> None:
        if node.is_end_of_word:
            results.append(current_prefix)

        for char, child_node in node.children.items():
            self._collect_all_words_from_node(child_node, current_prefix + char, results)

    def search_prefix(self, prefix: str) -> list:
        prefix_node = self._find_prefix_node(prefix)
        if prefix_node is None:
            return []

        results = []
        self._collect_all_words_from_node(prefix_node, prefix, results)
        return results
